function makeWallet(initial) {
  let balance = initial; // lives in the Lexical Environment of this call

  const deposit  = (amt) => { balance += amt; };
  const withdraw = (amt) => { balance -= amt; };
  const getBalance = ()  => balance;

  return { deposit, withdraw, getBalance };
  // All three closures share the SAME 'balance' binding
}

const walletA = makeWallet(100); // independent env, balance = 100
const walletB = makeWallet(500); // independent env, balance = 500

walletA.deposit(50);
console.log(walletA.getBalance()); // 150 — walletA's env
console.log(walletB.getBalance()); // 500 — walletB's env, untouched 

// deposit, withdraw, getBalance all share walletA's 'balance'
walletA.withdraw(30);
console.log(walletA.getBalance()); // 120

