// Simulated stale closure in a class method
class Counter {
  count = 0;

  incrementDelayed() {
    const snapshot = this.count; // captured at call time
    setTimeout(() => {
      // 'snapshot' is fixed; 'this.count' has moved on
      console.log('snapshot:', snapshot, '| current:', this.count);
    }, 1000);
    this.count++;
  }
}

const c = new Counter();
c.incrementDelayed(); // snapshot: 0 | current: 1 (after 1s)
